import{c as t,Q as a,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"I Tried 100+ Claude Code Skills. These 6 Are The Best","description":"","frontmatter":{"title":"I Tried 100+ Claude Code Skills. These 6 Are The Best","date":"2026-05-03T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-03-@nateherk-920535.md","filePath":"research/tweets/2026-05-03-@nateherk-920535.md","lastUpdated":1779894392000}'),o={name:"research/tweets/2026-05-03-@nateherk-920535.md"};function n(s,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="i-tried-100-claude-code-skills-these-6-are-the-best" tabindex="-1">I Tried 100+ Claude Code Skills. These 6 Are The Best <a class="header-anchor" href="#i-tried-100-claude-code-skills-these-6-are-the-best" aria-label="Permalink to &quot;I Tried 100+ Claude Code Skills. These 6 Are The Best&quot;">​</a></h1><p><strong>Author:</strong> <a href="https://x.com/nateherk" target="_blank" rel="noreferrer">@nateherk</a> (Nate Herk)<br><strong>Posted:</strong> Sun May 03 14:12:42 +0000 2026<br><strong>Original URL:</strong> <a href="https://x.com/nateherk/status/2050941624578920535" target="_blank" rel="noreferrer">https://x.com/nateherk/status/2050941624578920535</a></p><hr><h2 id="engagement-metrics" tabindex="-1">Engagement Metrics <a class="header-anchor" href="#engagement-metrics" aria-label="Permalink to &quot;Engagement Metrics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Count</th></tr></thead><tbody><tr><td>Views</td><td>61,472</td></tr><tr><td>Likes</td><td>549</td></tr><tr><td>Retweets</td><td>61</td></tr><tr><td>Bookmarks</td><td>1,312</td></tr><tr><td>Replies</td><td>8</td></tr></tbody></table><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Claude Code 六大實用技能：自動建造、流程管理、上下文優化、程式審查、記憶系統、前端設計。</p><hr><h2 id="core-arguments" tabindex="-1">Core Arguments <a class="header-anchor" href="#core-arguments" aria-label="Permalink to &quot;Core Arguments&quot;">​</a></h2><ol><li><strong>Automation First</strong>: The Factory skill enables Claude to auto-generate, test, and iterate skills—eliminating manual SKILL.md editing</li><li><strong>Process Discipline</strong>: Superpowers enforces senior-level development workflow (plan-before-code) to prevent rushed implementation failures</li><li><strong>Context Window Decay</strong>: Context Mode addresses the critical gotcha where ~40% of token space becomes garbage data after 30 min work, degrading quality</li><li><strong>Built-in Tooling</strong>: /review and Claude Mem are already available but underutilized—quick wins for immediate adoption</li><li><strong>GTM Strategy</strong>: Reframing skills as outcome-driven (time saving, cost cutting) rather than workflow features—improves sales effectiveness</li></ol><hr><h2 id="key-data-references" tabindex="-1">Key Data &amp; References <a class="header-anchor" href="#key-data-references" aria-label="Permalink to &quot;Key Data &amp; References&quot;">​</a></h2><ul><li><strong>400+ hours</strong> hands-on Claude Code experience (author credibility)</li><li><strong>6 core skills</strong> (specific number tested, not 10+ or 3)</li><li><strong>Playwright snapshot</strong>: 56 KB raw output</li><li><strong>20 GitHub issues</strong>: 59 KB raw output</li><li><strong>~30 min threshold</strong>: context degradation point identified</li><li><strong>Anthropic official</strong> frontend design skill mentioned</li><li><strong>Real-world validation</strong>: HVAC, real estate, coaches, marketing agencies</li></ul><hr><h2 id="critical-observations" tabindex="-1">Critical Observations <a class="header-anchor" href="#critical-observations" aria-label="Permalink to &quot;Critical Observations&quot;">​</a></h2><h3 id="a-overgeneralization-risk" tabindex="-1">A. Overgeneralization Risk <a class="header-anchor" href="#a-overgeneralization-risk" aria-label="Permalink to &quot;A. Overgeneralization Risk&quot;">​</a></h3><p>&#39;6 skills for every business&#39; may not apply to specialized domains (e.g., biotech research, financial modeling). Sample consists of SMBs, not enterprise or deep-tech sectors.</p><h3 id="b-implementation-gap" tabindex="-1">B. Implementation Gap <a class="header-anchor" href="#b-implementation-gap" aria-label="Permalink to &quot;B. Implementation Gap&quot;">​</a></h3><p>Article lists the skills but provides minimal detail on <em>how</em> to chain them effectively or what happens when they conflict (e.g., Factory vs GSD context limits).</p><h3 id="c-sales-framing-without-evidence" tabindex="-1">C. Sales Framing Without Evidence <a class="header-anchor" href="#c-sales-framing-without-evidence" aria-label="Permalink to &quot;C. Sales Framing Without Evidence&quot;">​</a></h3><p>Claims like &#39;save 10 hours/week&#39; are offered without benchmarks or case studies. Outcome-driven messaging is practical but unvalidated.</p><hr><h2 id="the-six-skills-detailed-breakdown" tabindex="-1">The Six Skills (Detailed Breakdown) <a class="header-anchor" href="#the-six-skills-detailed-breakdown" aria-label="Permalink to &quot;The Six Skills (Detailed Breakdown)&quot;">​</a></h2><h3 id="_1-the-factory-skill-creator" tabindex="-1">1. The Factory: Skill Creator <a class="header-anchor" href="#_1-the-factory-skill-creator" aria-label="Permalink to &quot;1. The Factory: Skill Creator&quot;">​</a></h3><p>Automates skill generation—users describe requirements in plain English, Claude drafts/tests/iterates. Eliminates manual SKILL.md editing.</p><h3 id="_2-the-process-superpowers" tabindex="-1">2. The Process: Superpowers <a class="header-anchor" href="#_2-the-process-superpowers" aria-label="Permalink to &quot;2. The Process: Superpowers&quot;">​</a></h3><p>Forces plan-before-code discipline. Prevents rushed implementation that fails under real client usage. Senior developer workflow enforcement.</p><h3 id="_3-the-clean-room-gsd" tabindex="-1">3. The Clean Room: GSD <a class="header-anchor" href="#_3-the-clean-room-gsd" aria-label="Permalink to &quot;3. The Clean Room: GSD&quot;">​</a></h3><p>Manages the environment where Claude writes code. Critical finding: context quality degrades around the halfway point (30+ min sessions).</p><h3 id="_4-the-safety-net-review-ultra-review" tabindex="-1">4. The Safety Net: /review + /ultra-review <a class="header-anchor" href="#_4-the-safety-net-review-ultra-review" aria-label="Permalink to &quot;4. The Safety Net: /review + /ultra-review&quot;">​</a></h3><p>Built-in structured code review. Catches bugs, edge cases, design issues. Local, fast, cost-neutral.</p><h3 id="_5-the-compressor-context-mode" tabindex="-1">5. The Compressor: Context Mode <a class="header-anchor" href="#_5-the-compressor-context-mode" aria-label="Permalink to &quot;5. The Compressor: Context Mode&quot;">​</a></h3><p>Addresses data garbage in context window (Playwright: 56 KB, 20 GitHub issues: 59 KB). After ~30 min work, 40% of context becomes noise.</p><h3 id="_6-the-memory-claude-mem" tabindex="-1">6. The Memory: Claude Mem <a class="header-anchor" href="#_6-the-memory-claude-mem" aria-label="Permalink to &quot;6. The Memory: Claude Mem&quot;">​</a></h3><p>Cross-session knowledge persistence. Eliminates re-explaining project setup for each new session.</p><h3 id="bonus-frontend-design" tabindex="-1">Bonus: Frontend Design <a class="header-anchor" href="#bonus-frontend-design" aria-label="Permalink to &quot;Bonus: Frontend Design&quot;">​</a></h3><p>Official Anthropic frontend design skill for visual/UI component generation. Reduces AI-generated appearance.</p><hr><h2 id="sales-strategy-outcome-driven" tabindex="-1">Sales Strategy (Outcome-Driven) <a class="header-anchor" href="#sales-strategy-outcome-driven" aria-label="Permalink to &quot;Sales Strategy (Outcome-Driven)&quot;">​</a></h2><p>Stop selling the workflow; sell the outcome:</p><ul><li>Saving the business owner 10 hours/week</li><li>Cutting admin mistakes and human error</li><li>Speeding up leads and conversions</li></ul><hr><h2 id="_5-dimension-evaluation-scoring" tabindex="-1">5-Dimension Evaluation Scoring <a class="header-anchor" href="#_5-dimension-evaluation-scoring" aria-label="Permalink to &quot;5-Dimension Evaluation Scoring&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Score</th><th>Rationale</th></tr></thead><tbody><tr><td><strong>A. Workspace Actionability</strong> (30%)</td><td>8/10</td><td>6 skills directly applicable; GSD/Context Mode/Superpowers already in workspace rules. Factory pattern reusable.</td></tr><tr><td><strong>B. Novelty</strong> (20%)</td><td>6/10</td><td>Known to advanced Claude Code users; novelty in Factory automation &amp; context quantification (56 KB metrics). GTM is common sense.</td></tr><tr><td><strong>C. Evidence Quality</strong> (20%)</td><td>6/10</td><td>400+ hours provides credibility; concrete data (Playwright 56 KB) but single sample. Missing control groups, failure cases, benchmarks.</td></tr><tr><td><strong>D. Technical Depth</strong> (15%)</td><td>5/10</td><td>Focuses on &#39;what&#39; not &#39;how&#39;. Context decay identified but mechanism unexplained. Factory flow underdocumented.</td></tr><tr><td><strong>E. Generalizability</strong> (15%)</td><td>5/10</td><td>Sample limited to SMBs (real estate, HVAC, coaches). May not apply to deep research, finance, biotech. No domain-specific variations.</td></tr><tr><td><strong>TOTAL</strong></td><td><strong>6.30/10</strong></td><td>Above threshold; candidate for knowledge capture.</td></tr></tbody></table><hr><h2 id="integration-decision" tabindex="-1">Integration Decision <a class="header-anchor" href="#integration-decision" aria-label="Permalink to &quot;Integration Decision&quot;">​</a></h2><p><strong>Status:</strong> RULE (通用原則) / Enhanced checklist for <code>.claude/skills/haiku-pilot</code> &amp; <code>.claude/rules/context-management.md</code></p><p><strong>Rationale:</strong> The 6 skills represent Claude Code operational best practices spanning workflow discipline (Superpowers), context management (Context Mode, GSD), and quality assurance (/review). Best captured as:</p><ul><li>Checklist updates in <code>haiku-pilot/SKILL.md</code></li><li>New rule section in <code>context-management.md</code> with 30-min degradation point</li><li>Reference example for workspace onboarding</li></ul><hr><h2 id="research-metadata" tabindex="-1">Research Metadata <a class="header-anchor" href="#research-metadata" aria-label="Permalink to &quot;Research Metadata&quot;">​</a></h2><ul><li><strong>Date Archived:</strong> 2026-05-04</li><li><strong>Source:</strong> Twitter Article (fxtwitter API)</li><li><strong>Archival Status:</strong> New</li><li><strong>Changeability:</strong> Content confirmed as final (no edits noted)</li></ul>',53)])])}const g=t(o,[["render",n]]);export{m as __pageData,g as default};
